const { Pool } = require\('pg'\);
const pool = new Pool\({
  host: 'heliosctadb.postgres.database.azure.com',
  user: 'helioscta',
  password: 'admin!2024',
  port: 5432,
  database: 'helioscta',
  ssl: { rejectUnauthorized: false },
  connectionTimeoutMillis: 15000,
}\);

async function run\(\) {
  const client = await pool.connect\(\);
  try {
    // Step 1: Create schema
    await client.query\('CREATE SCHEMA IF NOT EXISTS helioscta_app'\);
    console.log\('Schema created.'\);

    // Step 2: Create table
    await client.query\(\\`
      CREATE TABLE IF NOT EXISTS helioscta_app.genscape_noms_watchlists \(
        watchlist_id    SERIAL PRIMARY KEY,
        slug            VARCHAR\(100\) UNIQUE NOT NULL,
        display_name    VARCHAR\(255\) NOT NULL,
        location_role_ids INTEGER[] NOT NULL DEFAULT '{}',
        created_by      VARCHAR\(255\),
        is_active       BOOLEAN NOT NULL DEFAULT TRUE,
        created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW\(\),
        updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW\(\)
      \)
    \\`\);
    console.log\('Table created.'\);

    // Step 3: Seed KRS watchlist
    const res = await client.query\(\\`
      INSERT INTO helioscta_app.genscape_noms_watchlists \(slug, display_name, location_role_ids\)
      VALUES \('krs', 'KRS Watchlist', ARRAY[406012,446913,109286,144064,232367,232369,232371,232373,232375,232377,232379,232381,232383,232385,232397,232399]\)
      ON CONFLICT \(slug\) DO NOTHING
      RETURNING watchlist_id
    \\`\);
    if \(res.rowCount > 0\) {
      console.log\('KRS Watchlist seeded, id:', res.rows[0].watchlist_id\);
    } else {
      console.log\('KRS Watchlist already exists, skipped.'\);
    }

    // Step 4: Grant permissions
    await client.query\('GRANT USAGE ON SCHEMA helioscta_app TO helioscta'\);
    await client.query\('GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA helioscta_app TO helioscta'\);
    await client.query\('GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA helioscta_app TO helioscta'\);
    console.log\('Permissions granted.'\);

    // Verify
    const check = await client.query\('SELECT watchlist_id, slug, display_name, array_length\(location_role_ids,1\) as num_ids FROM helioscta_app.genscape_noms_watchlists'\);
    console.log\('Verification:', JSON.stringify\(check.rows, null, 2\)\);
  } finally {
    client.release\(\);
    await pool.end\(\);
  }
}

run\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
" 2>&1)
